local Input = {}; function Input:new() local input = {mousePosition = {x = 0, y = 0}, mouseDown = {}, keyDown = {}} setmetatable(input, self) self.__index = self return input end; function Input:setMousePosition(x, y) self.mousePosition.x = x self.mousePosition.y = y end; function Input:getMousePosition() return self.mousePosition end; function Input:setMouseDown(button, isDown) self.mouseDown[button] = isDown end; function Input:isMouseDown(button) return self.mouseDown[button] or false end; function Input:setKeyDown(key, isDown) self.keyDown[key] = isDown end; function Input:isKeyDown(key) return self.keyDown[key] or false end; return Input